class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        def is_k_palindromic(num):
            return str(num) == str(num)[::-1] and num % k == 0

        def can_be_rearranged(num):
            digits = sorted(str(num))
            for i in range(10**(n-1), 10**n):
                if is_k_palindromic(i) and sorted(str(i)) == digits:
                    return True
            return False

        count = 0
        for i in range(10**(n-1), 10**n):
            if can_be_rearranged(i):
                count += 1
        return count
